(function () {
  "use strict";

  const CONFIG = {
    containerSelector: "#animemory-board, .animemory-board",
    cardSelector: ".animemory-card",
    indexAttr: "data-index",
    highlightColor: "#22c55e", 
    highlightWidth: 4,
    scanInterval: 800, 
    debug: true,

    autoClick: true,
    delayBeforeMatchMin: 200, 
    delayBeforeMatchMax: 300, 
    delayBetweenClicksMin: 300, 
    delayBetweenClicksMax: 500,
    delayExploreMin: 200,
    delayExploreMax: 400,
  };

  let overlayRoot = null, running = false, intervalId = null, observer = null,
      panelEl = null, statusEl = null, targetContainer = null, playBtn = null, pauseBtn = null;

  const memory = new Map(); 
  const matchedIdx = new Set(); 
  let backSrc = null; 
  
  let isAutoClicking = false; 
  let isPlaying = false; 

  const delay = (ms) => new Promise(resolve => setTimeout(resolve, ms));
  const randomDelay = (min, max) => Math.floor(Math.random() * (max - min + 1)) + min;

  function detectBackSrc(cards) {
    const counts = new Map();
    cards.forEach((el) => {
      const img = el.querySelector("img");
      if (!img) return;
      const src = img.getAttribute("src");
      counts.set(src, (counts.get(src) || 0) + 1);
    });
    let best = null, max = 0;
    for (const [src, c] of counts) {
      if (c > max) { max = c; best = src; }
    }
    return best;
  }

  function scan() {
    const container = document.querySelector(CONFIG.containerSelector);
    if (!container) return null;
    const cards = Array.from(container.querySelectorAll(CONFIG.cardSelector));
    if (cards.length === 0) return null;

    if (!backSrc) backSrc = detectBackSrc(cards);

    const openNow = []; 

    cards.forEach((el) => {
      const idx = parseInt(el.getAttribute(CONFIG.indexAttr), 10);
      if (Number.isNaN(idx)) return;

      const img = el.querySelector("img");
      const src = img ? img.getAttribute("src") : null;
      const alt = img ? img.getAttribute("alt") : null;

      const isDisabledLike =
        el.disabled ||
        el.getAttribute("aria-disabled") === "true" ||
        /matched|solved|done|found/i.test(el.className);
      
      if (isDisabledLike) matchedIdx.add(idx);

      const isShowingFront = src && src !== backSrc;
      if (isShowingFront) {
        if (!memory.has(idx)) {
          memory.set(idx, alt || src);
        }
        if (!isDisabledLike) openNow.push(idx);
      }
    });

    return { cards, openNow, container };
  }

  function findKnownPairs() {
    const byId = new Map();
    for (const [idx, id] of memory) {
      if (matchedIdx.has(idx)) continue;
      if (!byId.has(id)) byId.set(id, []);
      byId.get(id).push(idx);
    }
    const pairs = [];
    for (const [id, idxs] of byId) {
      if (idxs.length >= 2) pairs.push({ id, indices: idxs });
    }
    return pairs;
  }

  function getUnrevealedIndices(meta) {
    return meta.cards
      .map(el => parseInt(el.getAttribute(CONFIG.indexAttr), 10))
      .filter(idx => !matchedIdx.has(idx) && !memory.has(idx) && !meta.openNow.includes(idx));
  }

  function clickCard(idx) {
    const btn = document.querySelector(`${CONFIG.cardSelector}[${CONFIG.indexAttr}="${idx}"]`);
    if (btn) btn.click();
  }

  function ensureOverlay() {
    if (overlayRoot && document.body.contains(overlayRoot)) return overlayRoot;
    const root = document.createElement("div");
    root.style.cssText = "position:fixed; top:0; left:0; width:0; height:0; z-index:999999; pointer-events:none;";
    document.body.appendChild(root);
    overlayRoot = root;
    return root;
  }
  
  function clearOverlay() { if (overlayRoot) overlayRoot.innerHTML = ""; }

  function boxFor(rect) {
    const pad = 4;
    const box = document.createElement("div");
    box.style.cssText = `
      position:fixed; left:${rect.left - pad}px; top:${rect.top - pad}px;
      width:${rect.width + pad * 2}px; height:${rect.height + pad * 2}px;
      border:${CONFIG.highlightWidth}px solid ${CONFIG.highlightColor};
      border-radius:10px; box-shadow:0 0 12px ${CONFIG.highlightColor};
      pointer-events:none;
    `;
    return box;
  }

  function drawHighlight(cards, indices) {
    const root = ensureOverlay();
    clearOverlay();
    if (!indices || indices.length === 0) return;
    indices.forEach((idx) => {
      const el = cards.find((c) => parseInt(c.getAttribute(CONFIG.indexAttr), 10) === idx);
      if (el) root.appendChild(boxFor(el.getBoundingClientRect()));
    });
  }

  function setStatus(text) {
    if (statusEl) statusEl.innerHTML = text;
  }

  function updateButtonStates() {
    if (!playBtn || !pauseBtn) return;
    if (isPlaying) {
      playBtn.style.opacity = "0.5"; playBtn.style.cursor = "not-allowed";
      pauseBtn.style.opacity = "1"; pauseBtn.style.cursor = "pointer";
    } else {
      playBtn.style.opacity = "1"; playBtn.style.cursor = "pointer";
      pauseBtn.style.opacity = "0.5"; pauseBtn.style.cursor = "not-allowed";
    }
  }

  function ensurePanel() {
    if (panelEl && document.body.contains(panelEl)) return;
    
    panelEl = document.createElement("div");
    panelEl.style.cssText = `position:fixed; right:16px; bottom:16px; z-index:1000000; background:rgba(0,0,0,0.85); padding:12px; border-radius:8px; font-family:sans-serif; width: 220px; box-shadow: 0 4px 6px rgba(0,0,0,0.3); color:#fff;`;
    
    const titleEl = document.createElement("div");
    titleEl.innerHTML = "<strong>🤖 AniMemory Bot</strong>";
    titleEl.style.marginBottom = "8px";
    panelEl.appendChild(titleEl);
    
    statusEl = document.createElement("div");
    statusEl.style.cssText = `color:#4ade80; font-size:13px; font-weight:bold; margin-bottom:12px;`;
    statusEl.innerHTML = "Siap dijalankan (Paused).";
    panelEl.appendChild(statusEl);

    const btnContainer = document.createElement("div");
    btnContainer.style.cssText = "display: flex; gap: 8px;";

    playBtn = document.createElement("button");
    playBtn.innerHTML = "▶ Play";
    playBtn.style.cssText = "flex: 1; background: #4ade80; color: #064e3b; border: none; padding: 6px; border-radius: 4px; font-weight: bold; transition: opacity 0.2s;";
    playBtn.onclick = () => {
      if (isPlaying) return;
      isPlaying = true;
      setStatus("Memindai kartu...");
      statusEl.style.color = "#4ade80";
      updateButtonStates();
      tick();
    };

    pauseBtn = document.createElement("button");
    pauseBtn.innerHTML = "⏸ Pause";
    pauseBtn.style.cssText = "flex: 1; background: #f87171; color: #7f1d1d; border: none; padding: 6px; border-radius: 4px; font-weight: bold; transition: opacity 0.2s;";
    pauseBtn.onclick = () => {
      if (!isPlaying) return;
      isPlaying = false;
      setStatus("Dihentikan (Paused).");
      statusEl.style.color = "#f87171";
      clearOverlay();
      updateButtonStates();
    };

    btnContainer.appendChild(playBtn);
    btnContainer.appendChild(pauseBtn);
    panelEl.appendChild(btnContainer);
    document.body.appendChild(panelEl);

    updateButtonStates();
  }

  async function tick() {
    if (!isPlaying) return; 
    if (isAutoClicking || !CONFIG.autoClick) return;

    const meta = scan();
    if (!meta) {
      setStatus("Menunggu board game...");
      return;
    }

    if (meta.openNow.length >= 2) {
      setStatus("Menunggu animasi game...");
      return;
    }

    if (meta.openNow.length === 1) {
      isAutoClicking = true;
      const openIdx = meta.openNow[0];
      const id = memory.get(openIdx);
      
      const twin = [...memory.entries()].find(([idx, val]) => idx !== openIdx && val === id && !matchedIdx.has(idx));

      if (twin) {
        drawHighlight(meta.cards, [twin[0]]);
        const waitTime = randomDelay(CONFIG.delayBetweenClicksMin, CONFIG.delayBetweenClicksMax);
        if(isPlaying) setStatus(`Jeda ${(waitTime/1000).toFixed(1)}s (Pasangan)...`);
        
        await delay(waitTime);
        if (!isPlaying) { isAutoClicking = false; return; } 
        clickCard(twin[0]);
      } else {
        const unrevealed = getUnrevealedIndices(meta);
        if (unrevealed.length > 0) {
          const randomIdx = unrevealed[Math.floor(Math.random() * unrevealed.length)];
          drawHighlight(meta.cards, [randomIdx]);
          const waitTime = randomDelay(CONFIG.delayExploreMin, CONFIG.delayExploreMax);
          if(isPlaying) setStatus(`Eksplorasi (Jeda ${(waitTime/1000).toFixed(1)}s)...`);
          
          await delay(waitTime);
          if (!isPlaying) { isAutoClicking = false; return; }
          clickCard(randomIdx);
        }
      }
      
      await delay(300); 
      isAutoClicking = false;
      if (isPlaying) tick();
      return;
    }

    if (meta.openNow.length === 0) {
      isAutoClicking = true;
      const pairs = findKnownPairs();

      if (pairs.length > 0) {
        const pair = pairs[0]; 
        drawHighlight(meta.cards, pair.indices);
        const waitTime = randomDelay(CONFIG.delayBeforeMatchMin, CONFIG.delayBeforeMatchMax);
        if(isPlaying) setStatus(`Ketemu Pasangan! (Jeda ${(waitTime/1000).toFixed(1)}s)`);
        
        await delay(waitTime);
        if (!isPlaying) { isAutoClicking = false; return; }
        clickCard(pair.indices[0]); 
      } else {
        const unrevealed = getUnrevealedIndices(meta);
        if (unrevealed.length > 0) {
          const randomIdx = unrevealed[Math.floor(Math.random() * unrevealed.length)];
          drawHighlight(meta.cards, [randomIdx]);
          const waitTime = randomDelay(CONFIG.delayExploreMin, CONFIG.delayExploreMax);
          if(isPlaying) setStatus(`Cari kartu baru (Jeda ${(waitTime/1000).toFixed(1)}s)`);
          
          await delay(waitTime);
          if (!isPlaying) { isAutoClicking = false; return; }
          clickCard(randomIdx);
        } else {
          // MODIFIKASI DI SINI: Tetap Play saat menunggu papan animasi level selesai.
          setStatus("Menunggu level selanjutnya...");
          clearOverlay();
        }
      }
      
      await delay(300);
      isAutoClicking = false;
      if (isPlaying) tick();
    }
  }

  function start() {
    if (running) return;
    running = true;
    ensurePanel();

    targetContainer = document.querySelector(CONFIG.containerSelector) || document.body;
    
    observer = new MutationObserver(() => {
        if(!isAutoClicking && isPlaying) tick();
    });
    observer.observe(targetContainer, { attributes: true, childList: true, subtree: true, attributeFilter: ["src", "class", "disabled", "aria-disabled"] });

    const toast = document.getElementById("animemory-toast");
    if (toast) {
      const toastObserver = new MutationObserver(() => {
        if (toast.classList.contains("show")) {
          isAutoClicking = true; 
          setTimeout(reset, 900); 
        }
      });
      toastObserver.observe(toast, { attributes: true, attributeFilter: ["class"] });
    }

    intervalId = setInterval(() => {
        if(!isAutoClicking && isPlaying) tick();
    }, CONFIG.scanInterval);
  }

  function stop() {
    running = false;
    isPlaying = false;
    if (intervalId) clearInterval(intervalId);
    if (observer) observer.disconnect();
    clearOverlay();
    if (panelEl) panelEl.remove();
  }

  function reset() {
    memory.clear();
    matchedIdx.clear();
    backSrc = null;
    clearOverlay();
    isAutoClicking = false; 
    
    if (isPlaying) tick();
  }

  if (window.AniMemoryBot && typeof window.AniMemoryBot.stop === "function") {
    window.AniMemoryBot.stop();
  }
  window.AniMemoryBot = { start, stop, reset, CONFIG, memory, matchedIdx };
  start();
})();
